SELECT COUNT(DISTINCT PB.PK) AS TOTAL FROM LATTES_P_PRODBIB LP JOIN SERVIDOR S ON S.PK_SIAPE = LP.FK_SIAPE JOIN LATTES_PRODBIB PB ON PB.PK = LP.FK_PRODBIB WHERE LOWER(S.GENERO) = LOWER('masculino') AND LOWER(COALESCE(S.SIGLA_CAMPUS, '')) = 'itu' AND LOWER(PB.NATUREZA) = LOWER('resumo expandido') AND LOWER(PB.PRODUCAO) LIKE LOWER('%libras%') AND (CASE WHEN PB.ANO GLOB '[0-9][0-9][0-9][0-9]' THEN CAST(PB.ANO AS INTEGER) ELSE NULL END) = 2023